class Solution(object):
    def punishmentNumber(self, n):
        def can_partition(s, target):
            # Can we partition string s into parts that sum to target?
            if not s:
                return target == 0
            for l in range(1, len(s) + 1):
                val = int(s[:l])
                if val <= target and can_partition(s[l:], target - val):
                    return True
            return False

        total = 0
        for i in range(1, n + 1):
            sq = i * i
            if can_partition(str(sq), i):
                total += sq
        return total
